class TestAcceptedFormats:
    """Files with allowed MIME types and extensions must be accepted."""

    def test_upload_pdf_succeeds(self, service, employee_id, valid_pdf):
        result = service.upload(employee_id=employee_id, **valid_pdf)
        assert result.status == "created"
        assert result.document_id != ""

    def test_upload_png_succeeds(self, service, employee_id, valid_png):
        result = service.upload(employee_id=employee_id, **valid_png)
        assert result.status == "created"

    def test_upload_jpg_succeeds(self, service, employee_id, valid_jpg):
        result = service.upload(employee_id=employee_id, **valid_jpg)
        assert result.status == "created"

    def test_upload_jpeg_extension_succeeds(self, service, employee_id):
        result = service.upload(
            employee_id=employee_id,
            filename="scan.jpeg",          # .jpeg variant
            content=_make_file(1024),
            mime_type="image/jpeg",
        )
        assert result.status == "created"

    def test_accepted_upload_returns_document_id(self, service, employee_id, valid_pdf):
        result = service.upload(employee_id=employee_id, **valid_pdf)
        assert isinstance(result.document_id, str)
        assert len(result.document_id) > 0


