class TestRejectedFormats:
    """Files with disallowed extensions or MIME types must be rejected."""

    @pytest.mark.parametrize(
        "filename, mime_type",
        [
            ("resume.docx", "application/vnd.openxmlformats-officedocument"
                            ".wordprocessingml.document"),
            ("spreadsheet.xlsx", "application/vnd.openxmlformats-officedocument"
                                 ".spreadsheetml.sheet"),
            ("archive.zip", "application/zip"),
            ("script.py", "text/x-python"),
            ("notes.txt", "text/plain"),
            ("image.gif", "image/gif"),
            ("image.bmp", "image/bmp"),
            ("page.html", "text/html"),
            ("data.csv", "text/csv"),
            ("binary.exe", "application/octet-stream"),
        ],
    )
    def test_disallowed_format_is_rejected(
        self, service, employee_id, filename, mime_type
    ):
        result = service.upload(
            employee_id=employee_id,
            filename=filename,
            content=_make_file(1024),
            mime_type=mime_type,
        )
        assert result.status == "rejected", (
            f"Expected rejection for {filename} ({mime_type}), got {result.status}"
        )
        assert result.document_id == ""

    def test_rejection_message_is_informative(self, service, employee_id):
        result = service.upload(
            employee_id=employee_id,
            filename="virus.exe",
            content=_make_file(1024),
            mime_type="application/octet-stream",
        )
        assert result.message, "Rejection must include a human-readable reason."

    def test_mismatched_extension_and_mime_type_is_rejected(
        self, service, employee_id
    ):
        """Extension says PDF but MIME type is HTML — must be rejected."""
        result = service.upload(
            employee_id=employee_id,
            filename="trick.pdf",
            content=_make_file(1024),
            mime_type="text/html",          # wrong MIME for the extension
        )
        assert result.status == "rejected"


