# 🔁 TC-004  Idempotency under retry
# ---------------------------------------------------------------------------


class TestIdempotency:
    """Retrying an upload must not create duplicate records."""

    # --- explicit idempotency key -----------------------------------------

    def test_second_upload_with_same_key_returns_same_document_id(
        self, service, employee_id, valid_pdf
    ):
        key = "idem-key-001"
        result_1 = service.upload(
            employee_id=employee_id, idempotency_key=key, **valid_pdf
        )
        result_2 = service.upload(
            employee_id=employee_id, idempotency_key=key, **valid_pdf
        )
        assert result_1.document_id == result_2.document_id

    def test_second_upload_with_same_key_has_already_exists_status(
        self, service, employee_id, valid_pdf
    ):
        key = "idem-key-002"
        service.upload(employee_id=employee_id, idempotency_key=key, **valid_pdf)
        result = service.upload(
            employee_id=employee_id, idempotency_key=key, **valid_pdf
        )
        assert result.status == "already_exists"

    def test_three_retries_with_same_key_all_return_same_document_id(
        self, service, employee_id, valid_pdf
    ):
        key = "idem-key-003"
        ids = [
            service.upload(
                employee_id=employee_id, idempotency_key=key, **valid_pdf
            ).document_id
            for _ in range(3)
        ]
        assert len(set(ids)) == 1, "All retries must return the same document_id."

    # --- content-hash idempotency (no explicit key) -----------------------

    def test_duplicate_content_without_key_returns_same_document_id(
        self, service, employee_id, valid_png
    ):
        result_1 = service.upload(employee_id=employee_id, **valid_png)
        result_2 = service.upload(employee_id=employee_id, **valid_png)
        assert result_1.document_id == result_2.document_id

    def test_duplicate_content_without_key_does_not_create_new_record(
        self, service, employee_id, valid_png
    ):
        service.upload(employee_id=employee_id, **valid_png)
        result = service.upload(employee_id=employee_id, **valid_png)
        assert result.status == "already_exists"

    def test_different_content_creates_new_document(
        self, service, employee_id
    ):
        r1 = service.upload(
            employee_id=employee_id,
            filename="a.pdf",
            content=_make_file(100),
            mime_type="application/pdf",
        )
        r2 = service.upload(
            employee_id=employee_id,
            filename="b.pdf",
            content=_make_file(200),    # different size ⇒ different checksum
            mime_type="application/pdf",
        )
        assert r1.document_id != r2.document_id
        assert r2.status == "created"

    def test_different_idempotency_keys_create_separate_documents(
        self, service, employee_id
    ):
        key_a, key_b = "key-A", "key-B"
        r1 = service.upload(
            employee_id=employee_id,
            idempotency_key=key_a,
            filename="contract.pdf",
            content=_make_file(1024),
            mime_type="application/pdf",
        )
        r2 = service.upload(
            employee_id=employee_id,
            idempotency_key=key_b,
            filename="contract.pdf",
            content=_make_file(1024),
            mime_type="application/pdf",
        )
        # Same content but different keys ⇒ implementation-defined;
        # what matters is neither call returns "rejected".
        assert r1.status in {"created", "already_exists"}
        assert r2.status in {"created", "already_exists"}

    # --- retry on simulated transient failure -----------------------------

    def test_idempotency_after_simulated_network_retry(
        self, service, employee_id, valid_jpg
    ):
        """
        Simulate: first attempt raises a network error, client retries with
        the same idempotency key; the second call must succeed and not
        create a duplicate.
        """
        key = "retry-key-net-001"

        call_count = 0
        original_upload = service.upload

        def flaky_upload(**kwargs):
            nonlocal call_count
            call_count += 1
            if call_count == 1:
                raise ConnectionError("Simulated network failure on first attempt.")
            return original_upload(**kwargs)

        service.upload = flaky_upload  # type: ignore[method-assign]

        with pytest.raises(ConnectionError):
            service.upload(employee_id=employee_id, idempotency_key=key, **valid_jpg)

        # Retry
        service.upload = original_upload  # restore
        result = service.upload(
            employee_id=employee_id, idempotency_key=key, **valid_jpg
        )
        assert result.status in {"created", "already_exists"}
        assert result.document_id != ""

    def test_rejected_upload_is_not_stored_for_idempotency(
        self, service, employee_id, oversized_file
    ):
        """
        A rejected upload must NOT be remembered as a successful idempotent
        record — a corrected retry must be processed fresh.
        """
        key = "idem-reject-key"

        rejected = service.upload(
            employee_id=employee_id, idempotency_key=key, **oversized_file
        )
        assert rejected.status == "rejected"

        # Now retry with a valid payload using the same idempotency key.
        fixed_payload = {
            "filename": oversized_file["filename"],
            "content": _make_file(1 * 1024 * 1024),  # within limit
            "mime_type": oversized_file["mime_type"],
        }
        retry = service.upload(
            employee_id=employee_id, idempotency_key=key, **fixed_payload
        )
        # The corrected file must be accepted.
        assert retry.status in {"created", "already_exists"}
        assert retry.document_id != ""


# ---------------------------------------------------------------------------
# 🔀 TC-005  Combined edge cases
# ---------------------------------------------------------------------------


class TestCombinedEdgeCases:
    """Cross-cutting scenarios combining format, size, and idempotency rules."""

    def test_oversized_file_rejected_regardless_of_idempotency_key(
        self, service, employee_id, oversized_file
    ):
        result = service.upload(
            employee_id=employee_id,
            idempotency_key="over-idem",
            **oversized_file,
        )
        assert result.status == "rejected"

    def test_invalid_format_rejected_regardless_of_idempotency_key(
        self, service, employee_id
    ):
        result = service.upload(
            employee_id=employee_id,
            idempotency_key="fmt-idem",
            filename="evil.exe",
            content=_make_file(1024),
            mime_type="application/octet-stream",
        )
        assert result.status == "rejected"

    def test_multiple_employees_can_upload_same_filename(self, service):
        """Two employees uploading identically-named files are independent."""
        kwargs = {
            "filename": "offer_letter.pdf",
            "content": _make_file(1024),
            "mime_type": "application/pdf",
        }
        r1 = service.upload(employee_id="emp-100", **kwargs)
        r2 = service.upload(employee_id="emp-200", **kwargs)
        # Both must succeed (content hash idempotency may unify them, but
        # neither should be rejected).
        assert r1.status in {"created", "already_exists"}
        assert r2.status in {"created", "already_exists"}

    def test_upload_with_uppercase_extension_is_handled(
        self, service, employee_id
    ):
        """
        Filenames like 'PHOTO.PNG' are common; the service should handle
        them gracefully (accept or reject consistently — not crash).
        """
        result = service.upload(
            employee_id=employee_id,
            filename="PHOTO.PNG",
            content=_make_file(512),
            mime_type="image/png",
        )
        # If the service normalises extensions, this is "created";
        # if it is case-sensitive and rejects uppercase, "rejected" is fine
        # as long as the response is well-formed.
        assert result.status in {"created", "rejected"}
        assert isinstance(result.document_id, str)
